for (let i = 0; i < array.length && i < OBJECT_WIDTH_LIMIT; i++) {
  const value = array[i];
  if (typeof value === 'object' && value !== null) {
    if (
      isArray(value) &&
      value.length === 2 &&
      typeof value[0] === 'string'
    ) {
      // Key value tuple
      if (kind !== EMPTY_ARRAY && kind !== ENTRIES_ARRAY) {
        return COMPLEX_ARRAY;
      }
      kind = ENTRIES_ARRAY;
    } else {
      return COMPLEX_ARRAY;
    }
  } else if (typeof value === 'function') {
    return COMPLEX_ARRAY;
  } else if (typeof value === 'string' && value.length > 50) {
    return COMPLEX_ARRAY;
  } else if (kind !== EMPTY_ARRAY && kind !== PRIMITIVE_ARRAY) {
    return COMPLEX_ARRAY;
  } else if (typeof value === 'bigint') {
    return COMPLEX_ARRAY;
  } else {
    kind = PRIMITIVE_ARRAY;
  }
}

if (this.orientation === 'horizontal') {
  let pageX = Math.min(
    this.layoutDelegate.getContentSize().width,
    itemRect.x - itemRect.width + this.layoutDelegate.getVisibleRect().width
  );

  while (itemRect && itemRect.x < pageX && nextKey != null) {
    nextKey = this.getKeyBelow(nextKey);
    itemRect = nextKey == null ? null : this.layoutDelegate.getItemRect(nextKey);
  }
} else {
  let pageY = Math.min(
    this.layoutDelegate.getContentSize().height,
    itemRect.y - itemRect.height + this.layoutDelegate.getVisibleRect().height
  );

  while (itemRect && itemRect.y < pageY && nextKey != null) {
    nextKey = this.getKeyBelow(nextKey);
    itemRect = nextKey == null ? null : this.layoutDelegate.getItemRect(nextKey);
  }
}

