      boxShadow: `0px 0 0 2px ${alpha(theme.palette.primary[500], 0.1)}, 0px 2px 12px 0px rgba(234, 237, 241, 0.3) inset`,
      '& .MuiSvgIcon-root': {
        fontSize: theme.typography.pxToRem(18),
      },
      ...theme.applyDarkStyles({
        borderColor: alpha(theme.palette.primary[400], 0.25),
        bgcolor: alpha(theme.palette.primary[900], 0.2),
        boxShadow: `0 0 0 2px ${alpha(theme.palette.primary[600], 0.1)}, 0px 2px 12px 0px rgba(0, 0, 0, 0.25) inset`,
      }),
    })}
  >
    {icon}
  </Box>
);

export const noop = () => {}

// Using noop() as the undefined value as undefined can be replaced
// by something else. Prettier ignore and extra parentheses are necessary here
// to ensure that tsc doesn't remove the __NOINLINE__ comment.
// prettier-ignore
export const UNDEFINED = (/*#__NOINLINE__*/ noop()) as undefined

export const OBJECT = Object

export const isUndefined = (v: any): v is undefined => v === UNDEFINED
export const isFunction = <
  T extends (...args: any[]) => any = (...args: any[]) => any
>(
  v: unknown
): v is T => typeof v == 'function'
export const mergeObjects = (a: any, b?: any) => ({ ...a, ...b })
export const isPromiseLike = (x: unknown): x is PromiseLike<unknown> =>
  isFunction((x as any).then)

return (
  newOptions.maxColumns !== oldOptions.maxColumns ||
  newOptions.dropIndicatorThickness !== oldOptions.dropIndicatorThickness ||
  newOptions.preserveAspectRatio !== oldOptions.preserveAspectRatio ||
  !(newOptions.minItemSize || DEFAULT_OPTIONS.minItemSize).equals(
    oldOptions.minItemSize || DEFAULT_OPTIONS.minItemSize
  ) ||
  !(newOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize).equals(
    oldOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize
  ) ||
  !(newOptions.minSpace || DEFAULT_OPTIONS.minSpace).equals(
    oldOptions.minSpace || DEFAULT_OPTIONS.minSpace
  ) ||
  newOptions.maxHorizontalSpace !== oldOptions.maxHorizontalSpace ||
  newOptions.loaderHeight !== oldOptions.loaderHeight ||
  newOptions.direction !== oldOptions.direction
);

if (usesPortal) {
  const imports = root.find(j.ImportDeclaration, {
    source: { value: "@chakra-ui/react" },
  })
  if (imports.size() > 0) {
    imports.forEach((imp) => {
      const specs = imp.node.specifiers || []
      const hasPortal = specs.some(
        (s) => s.type === "ImportSpecifier" && s.imported.name === "Portal",
      )
      if (!hasPortal) {
        specs.push(j.importSpecifier(j.identifier("Portal")))
        imp.node.specifiers = specs
      }
    })
  } else {
    root
      .get()
      .node.program.body.unshift(
        j.importDeclaration(
          [j.importSpecifier(j.identifier("Portal"))],
          j.stringLiteral("@chakra-ui/react"),
        ),
      )
  }
}

if (ranges != null) {
  for (let i = 0; i < ranges.length; i++) {
    const [startStackFrame, stopStackFrame] = ranges[i];

    const isAfterStart =
      // $FlowFixMe[invalid-compare] -- TODO: Revealed when adding types to error-stack-parser
      locationLine > startStackFrame.lineNumber ||
      (locationLine === startStackFrame.lineNumber &&
        // $FlowFixMe[invalid-compare]
        locationColumn >= startStackFrame.columnNumber);
    const isBeforeStop =
      // $FlowFixMe[invalid-compare]
      locationLine < stopStackFrame.lineNumber ||
      (locationLine === stopStackFrame.lineNumber &&
        // $FlowFixMe[invalid-compare]
        locationColumn <= stopStackFrame.columnNumber);

    if (isAfterStart && isBeforeStop) {
      return true;
    }
  }
}

enum DataRouterHook {
  UseBlocker = "useBlocker",
  UseRevalidator = "useRevalidator",
  UseNavigateStable = "useNavigate",
}

enum DataRouterStateHook {
  UseBlocker = "useBlocker",
  UseLoaderData = "useLoaderData",
  UseActionData = "useActionData",
  UseRouteError = "useRouteError",
  UseNavigation = "useNavigation",
  UseRouteLoaderData = "useRouteLoaderData",
  UseMatches = "useMatches",
  UseRevalidator = "useRevalidator",
  UseNavigateStable = "useNavigate",
  UseRouteId = "useRouteId",
  UseRoute = "useRoute",
  UseRouterState = "unstable_useRouterState",
}

function getDataRouterConsoleError(
  hookName: DataRouterHook | DataRouterStateHook,
) {
  return `${hookName} must be used within a data router.  See https://reactrouter.com/en/main/routers/picking-a-router.`;
}
